mapper.sql:
SELECT A.ATCL_ID , B.ORG_ID , A.BBS_ID , A.USER_ID , C.UP_ATCL_CMNT_ID , A.ATCL_TTL , A.ATCL_LV , A.ATCL_SEQNO , C.ATCL_CMNT_ID , C.UP_ATCL_CMNT_ID , C.ATCL_CMNT_CTS AS ATCL_CMNT_CTS , C.EMTICN_NO , (SELECT USERNM FROM TB_LMS_USER WHERE USER_ID = A.USER_ID) AS RGTR_NM , C.REG_DTTM , C.DELYN FROM TB_LMS_BBS_ATCL A JOIN TB_LMS_BBS B ON A.BBS_ID = B.BBS_ID JOIN TB_LMS_BBS_ATCL_CMNT C ON A.ATCL_ID = C.ATCL_ID WHERE 1=1 AND A.BBS_ID = #{bbsId} AND A.ATCL_ID = #{atclId}
AND B.ORG_ID = #{orgId}
ORDER BY A.REG_DTTM DESC

mapper.select:
