             SQL ID : BbsCmntDAO.countBbsCmnt
             설  명 : 댓글 목록 수
         */
		SELECT COUNT(1) FROM (

		) Z

mapper.insert:
		/*
             SQL ID : BbsCmntDAO.insertBbsCmnt
             설  명 : 댓글 저장
         */
		INSERT INTO TB_LMS_BBS_ATCL_CMNT (
			  ATCL_CMNT_ID
			, ATCL_ID
			, UP_ATCL_CMNT_ID
			, ATCL_CMNT_CTS
			, EMTICN_NO
			, DELYN
			, RGTR_ID
			, RGTRNM
			, FRST_INQ_DTTM
		) VALUES (
			  #{cmntId}
			, #{atclId}
			, #{parCmntId}
			, #{cmntCts}
			, #{emoticonNo}
			, 'N'
			, #{rgtrId}
			, (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = #{rgtrId})
			, FN_DTTM()
		)

mapper.update:
		/*
             SQL ID : BbsCmntDAO.updateBbsCmnt
             설  명 : 댓글 수정
         */
		UPDATE TB_LMS_BBS_ATCL_CMNT
		SET
			  ATCL_CMNT_CTS    = #{cmntCts}
			, MDFR_ID      = #{mdfrId}
			, MOD_DTTM    = FN_DTTM()
		WHERE ATCL_CMNT_ID = #{cmntId}
		AND ATCL_ID = #{atclId}

		/*
             SQL ID : BbsCmntDAO.updateBbsCmntDelY
             설  명 : 댓글 삭제 수정
         */
		UPDATE TB_LMS_BBS_ATCL_CMNT
		SET
			  DELYN	  = 'Y'
			, MDFR_ID      = #{mdfrId}
			, MOD_DTTM    = FN_DTTM()
		WHERE ATCL_CMNT_ID = #{cmntId}
		AND ATCL_ID = #{atclId}

mapper.delete:
		/*
             SQL ID : BbsCmntDAO.deleteBbsCmnt
             설  명 : 댓글 삭제
         */
		DELETE FROM TB_LMS_BBS_ATCL_CMNT
		WHERE ATCL_CMNT_ID = #{cmntId}
		AND ATCL_ID = #{atclId}

		/*
             SQL ID : BbsCmntDAO.deleteBbsCmntAll
             설  명 : 댓글 전체 삭제
         */
		DELETE FROM TB_LMS_BBS_ATCL_CMNT
		WHERE ATCL_ID = #{atclId}
